CREATE DATABASE IF NOT EXISTS ka_hulaan_game CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE ka_hulaan_game;
SET FOREIGN_KEY_CHECKS = 0;
DROP TABLE IF EXISTS user_rewards;
DROP TABLE IF EXISTS user_progress;
DROP TABLE IF EXISTS tile_options;
DROP TABLE IF EXISTS scenario_clues;
DROP TABLE IF EXISTS scenarios;
DROP TABLE IF EXISTS rewards;
DROP TABLE IF EXISTS game_modes;
DROP TABLE IF EXISTS users;
SET FOREIGN_KEY_CHECKS = 1;
CREATE TABLE users (
  user_id INT AUTO_INCREMENT PRIMARY KEY,
  full_name VARCHAR(120) NOT NULL,
  email VARCHAR(120) NOT NULL UNIQUE,
  password_hash VARCHAR(255) NOT NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB;
CREATE TABLE game_modes (
  mode_id INT AUTO_INCREMENT PRIMARY KEY,
  mode_key VARCHAR(50) NOT NULL UNIQUE,
  mode_name VARCHAR(80) NOT NULL,
  description TEXT NOT NULL
) ENGINE=InnoDB;
CREATE TABLE scenarios (
  scenario_id INT AUTO_INCREMENT PRIMARY KEY,
  mode_id INT NOT NULL,
  title VARCHAR(140) NOT NULL,
  prompt TEXT NOT NULL,
  answer VARCHAR(255) NOT NULL,
  hint TEXT NOT NULL,
  learning_tip TEXT NOT NULL,
  difficulty ENUM('Easy','Medium','Hard') NOT NULL DEFAULT 'Easy',
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT fk_scenarios_mode FOREIGN KEY (mode_id) REFERENCES game_modes(mode_id) ON DELETE CASCADE,
  UNIQUE KEY unique_mode_title (mode_id, title)
) ENGINE=InnoDB;
CREATE TABLE scenario_clues (
  clue_id INT AUTO_INCREMENT PRIMARY KEY,
  scenario_id INT NOT NULL,
  clue_order TINYINT NOT NULL,
  clue_title VARCHAR(100) NOT NULL,
  clue_text TEXT NOT NULL,
  CONSTRAINT fk_clues_scenario FOREIGN KEY (scenario_id) REFERENCES scenarios(scenario_id) ON DELETE CASCADE,
  UNIQUE KEY unique_clue_order (scenario_id, clue_order)
) ENGINE=InnoDB;
CREATE TABLE tile_options (
  option_id INT AUTO_INCREMENT PRIMARY KEY,
  scenario_id INT NOT NULL,
  option_text VARCHAR(255) NOT NULL,
  is_correct TINYINT(1) NOT NULL DEFAULT 0,
  CONSTRAINT fk_options_scenario FOREIGN KEY (scenario_id) REFERENCES scenarios(scenario_id) ON DELETE CASCADE
) ENGINE=InnoDB;
CREATE TABLE user_progress (
  progress_id INT AUTO_INCREMENT PRIMARY KEY,
  user_id INT NOT NULL,
  scenario_id INT NOT NULL,
  mode_id INT NOT NULL,
  is_correct TINYINT(1) NOT NULL DEFAULT 0,
  attempts INT NOT NULL DEFAULT 0,
  score_awarded INT NOT NULL DEFAULT 0,
  completed_at DATETIME NULL,
  CONSTRAINT fk_progress_user FOREIGN KEY (user_id) REFERENCES users(user_id) ON DELETE CASCADE,
  CONSTRAINT fk_progress_scenario FOREIGN KEY (scenario_id) REFERENCES scenarios(scenario_id) ON DELETE CASCADE,
  CONSTRAINT fk_progress_mode FOREIGN KEY (mode_id) REFERENCES game_modes(mode_id) ON DELETE CASCADE,
  UNIQUE KEY unique_user_scenario (user_id, scenario_id)
) ENGINE=InnoDB;
CREATE TABLE rewards (
  reward_id INT AUTO_INCREMENT PRIMARY KEY,
  badge_key VARCHAR(60) NOT NULL UNIQUE,
  badge_name VARCHAR(100) NOT NULL,
  description TEXT NOT NULL,
  requirement_type VARCHAR(60) NOT NULL,
  requirement_value INT NOT NULL,
  icon VARCHAR(10) NOT NULL
) ENGINE=InnoDB;
CREATE TABLE user_rewards (
  user_reward_id INT AUTO_INCREMENT PRIMARY KEY,
  user_id INT NOT NULL,
  reward_id INT NOT NULL,
  awarded_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT fk_user_rewards_user FOREIGN KEY (user_id) REFERENCES users(user_id) ON DELETE CASCADE,
  CONSTRAINT fk_user_rewards_reward FOREIGN KEY (reward_id) REFERENCES rewards(reward_id) ON DELETE CASCADE,
  UNIQUE KEY unique_user_reward (user_id, reward_id)
) ENGINE=InnoDB;
